'use client';
import { ChevronDown, Bell, Search } from 'lucide-react';
import { SidebarProps } from '@/components/ui/Sidebars';
import { useAuth } from '@/context/AuthContext';
import SearchInput from './SearchInput';

const DashboardHeader = ({ sidebarOpen, setSidebarOpen }: SidebarProps) => {
  const { userRole, detailsProfile } = useAuth();

  return (
    <header className='bg-white shadow-sm z-10 m-4'>
      <div className='flex items-center justify-between p-4'>
        <div className='flex items-center'>
          <button
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className='p-2 rounded-lg hover:bg-gray-100 mr-2'
          >
            <svg
              className='w-5 h-5'
              fill='none'
              stroke='currentColor'
              viewBox='0 0 24 24'
            >
              <path
                strokeLinecap='round'
                strokeLinejoin='round'
                strokeWidth='2'
                d='M4 6h16M4 12h16M4 18h16'
              />
            </svg>
          </button>
          {/* Search Input */}
          <SearchInput name='' />
        </div>

        <div className='flex items-center space-x-4'>
          <div className='relative'>
            <button className='p-2 rounded-full hover:bg-gray-100 relative'>
              <Bell className='text-gray-600 w-5 h-5' />
              {[1, 2, 3].some((n) => !n?.read) && (
                <span className='absolute top-0 right-0 w-2 h-2 bg-red-500 rounded-full'></span>
              )}
            </button>
          </div>
          <div className='flex items-center space-x-2'>
            <div className='w-8 h-8 bg-indigo-100 rounded-full flex items-center justify-center'>
              <span className='text-indigo-800 font-medium'>
                {detailsProfile?.name[0]}
              </span>
            </div>

            <div>
              <p className='text-sm font-medium'>{detailsProfile?.name}</p>
              {userRole === 'host' ? (
                <p className='text-xs text-gray-500'>
                  {detailsProfile?.hostCategory}
                </p>
              ) : (
                <></>
              )}
            </div>
            <ChevronDown className='text-gray-500 w-5 h-5' />
          </div>
        </div>
      </div>
    </header>
  );
};
export default DashboardHeader;
