'use client';
import Link from 'next/link';
import { useAuth } from '@/context/AuthContext';
import { adminNavItems, hostNavItems } from '@/constants/navItems';
import { LogOut } from 'lucide-react';
import { AnimatePresence, motion } from 'framer-motion';

export interface SidebarProps {
  sidebarOpen: boolean;
  setSidebarOpen: (open: boolean) => void;
}

const Sidebars = ({ sidebarOpen, setSidebarOpen }: SidebarProps) => {
  const { logout, userRole } = useAuth();
  const handleLogout = () => {
    logout();
  };

  return (
    <AnimatePresence>
      {sidebarOpen && (
        <motion.aside
          initial={{ x: -300, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          exit={{ x: -300, opacity: 0 }}
          transition={{ type: 'spring', damping: 25 }}
          className={`w-64 relative bg-gradient-to-r from-purple-900 to-pink-900 text-white shadow-xl`}
        >
          <div className='h-full flex flex-col'>
            <div className='p-4 border-b'>
              <h1 className='text-xl font-bold'>UniJoy {userRole}</h1>
            </div>

            <nav className='flex-1 p-4 space-y-2'>
              {userRole === 'admin'
                ? adminNavItems.map((item, index) => (
                    <Link
                      key={index}
                      href={item.href}
                      className={`flex items-center gap-3 p-3 rounded-lg hover:bg-purple-700`}
                    >
                      {item.icon}
                      <span>{item.label}</span>
                    </Link>
                  ))
                : hostNavItems.map((item, index) => (
                    <Link
                      key={index}
                      href={item.href}
                      className={`flex items-center gap-3 p-3 rounded-lg hover:bg-purple-700`}
                    >
                      {item.icon}
                      <span>{item.label}</span>
                    </Link>
                  ))}
            </nav>
            {/* Section Logout */}
            <div className='p-4 border-t'>
              <button
                className={`w-full flex items-center gap-3 p-3 rounded-lg hover:bg-purple-700`}
              >
                <LogOut className='w-5 h-5' />
                <span onClick={handleLogout}>Logout</span>
              </button>
            </div>
          </div>
        </motion.aside>
      )}
    </AnimatePresence>
  );
};

export default Sidebars;
